namespace sv_3eac785e2caf4f87ac0d2758bffa3777.Services;

/// <summary>
/// Scoped service holding the currently selected warehouse for a single user circuit.
/// Components subscribe to <see cref="OnChange"/> to react when the selection changes.
/// </summary>
public class WarehouseState
{
    public string SelectedWarehouseId { get; private set; } = "WH-001";

    public event Action? OnChange;

    public static IReadOnlyList<(string Id, string Name)> AvailableWarehouses { get; } =
    [
        ("WH-001", "Warehouse A — Main Distribution"),
        ("WH-002", "Warehouse B — East Regional"),
        ("WH-003", "Warehouse C — West Regional"),
    ];

    public void SetWarehouse(string warehouseId)
    {
        if (SelectedWarehouseId == warehouseId) return;
        SelectedWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

