@rendermode InteractiveServer
@inject WarehouseState WarehouseState
@implements IDisposable
@using sv_3eac785e2caf4f87ac0d2758bffa3777.Services

<div class="warehouse-selector">
    <label class="form-label text-white mb-1" for="warehouseSelect">Current Warehouse</label>
    <select id="warehouseSelect"
            class="form-select form-select-sm"
            value="@WarehouseState.SelectedWarehouseId"
            @onchange="OnWarehouseChanged">
        @foreach (var wh in WarehouseState.AvailableWarehouses)
        {
            <option value="@wh.Id">@wh.Name</option>
        }
    </select>
</div>

@code {
    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        var id = e.Value?.ToString();
        if (!string.IsNullOrEmpty(id))
        {
            WarehouseState.SetWarehouse(id);
        }
    }

    // Subscribe so this component re-renders if another component changes the warehouse.
    protected override void OnInitialized()
    {
        WarehouseState.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= StateHasChanged;
    }
}

@rendermode InteractiveServer
@inject InventoryAlertState AlertState
@implements IDisposable
@using sv_3eac785e2caf4f87ac0d2758bffa3777.Services

@if (AlertState.LowStockCount > 0)
{
    <span class="badge bg-danger rounded-pill ms-2" title="Low-stock items">
        @AlertState.LowStockCount
    </span>
}
else
{
    <span class="badge bg-success rounded-pill ms-2" title="No low-stock alerts">
        0
    </span>
}

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        // Wrap in InvokeAsync because the event may fire from a timer on another component.
        _handler = () => InvokeAsync(StateHasChanged);
        AlertState.OnChange += _handler;
    }

    public void Dispose()
    {
        AlertState.OnChange -= _handler;
    }
}

