+                <span class="text-muted">ID: @WarehouseState.SelectedWarehouseId</span>
+            </div>
+        </div>
+    </div>
+    <div class="col-md-6">
+        <div class="card @(AlertState.LowStockCount > 0 ? "border-danger" : "border-success")">
+            <div class="card-body">
+                <h5 class="card-title">Low-Stock Alerts</h5>
+                <p class="card-text fs-1 @(AlertState.LowStockCount > 0 ? "text-danger" : "text-success")">
+                    @AlertState.LowStockCount
+                    <AlertBadge />
+                </p>
+                <span class="text-muted">
+                    Polling every 10 seconds &bull; Last check: @_lastCheck?.ToString("HH:mm:ss")
+                </span>
+            </div>
+        </div>
+    </div>
+</div>
+
+@if (_pollHistory.Count > 0)
+{
+    <h4>Recent Alert History</h4>
+    <table class="table table-sm table-striped">
+        <thead>
+            <tr><th>Time</th><th>Warehouse</th><th>Low-Stock Count</th></tr>
+        </thead>
+        <tbody>
+            @foreach (var entry in _pollHistory)
+            {
+                <tr>
+                    <td>@entry.Time.ToString("HH:mm:ss")</td>
+                    <td>@entry.WarehouseId</td>
+                    <td>
+                        <span class="badge @(entry.Count > 0 ? "bg-danger" : "bg-success")">
+                            @entry.Count
+                        </span>
+                    </td>
+                </tr>
+            }
+        </tbody>
+    </table>
+}
+
+@code {
+    private PeriodicTimer? _timer;
+    private CancellationTokenSource? _cts;
+    private DateTime? _lastCheck;
+    private Action? _warehouseHandler;
+    private Action? _alertHandler;
+    private readonly List<PollEntry> _pollHistory = [];
+
+    protected override async Task OnInitializedAsync()
+    {
+        // Subscribe to warehouse changes so the dashboard re-renders immediately.
+        _warehouseHandler = () => InvokeAsync(async () =>
+        {
+            // Warehouse changed — poll immediately for the new warehouse.
+            await PollAsync();
+            StateHasChanged();
+        });
+        WarehouseState.OnChange += _warehouseHandler;
+
+        // Subscribe to alert state so this component updates when any poll fires.
+        _alertHandler = () => InvokeAsync(StateHasChanged);
+        AlertState.OnChange += _alertHandler;
+
+        // Initial poll + start timer.
+        await PollAsync();
+        StartPolling();
+    }
+
+    private void StartPolling()
+    {
+        _cts = new CancellationTokenSource();
+        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
+        _ = PollLoopAsync(_cts.Token);
+    }
+
+    private async Task PollLoopAsync(CancellationToken ct)
+    {
+        try
+        {
+            while (await _timer!.WaitForNextTickAsync(ct))
+            {
+                await InvokeAsync(async () =>
+                {
+                    await PollAsync();
+                    StateHasChanged();
+                });
+            }
+        }
+        catch (OperationCanceledException)
+        {
+            // Expected on dispose.
+        }
+    }
+
+    private async Task PollAsync()
+    {
+        var warehouseId = WarehouseState.SelectedWarehouseId;
+        var count = await AlertService.GetLowStockCountAsync(warehouseId);
+        _lastCheck = DateTime.Now;
+
+        _pollHistory.Insert(0, new PollEntry(DateTime.Now, warehouseId, count));
+        if (_pollHistory.Count > 10) _pollHistory.RemoveAt(_pollHistory.Count - 1);
+
+        // Push to shared state — this notifies the sidebar AlertBadge and any other subscriber.
+        AlertState.Update(count);
+    }
+
+    public void Dispose()
+    {
+        _cts?.Cancel();
+        _cts?.Dispose();
+        _timer?.Dispose();
+
+        if (_warehouseHandler is not null) WarehouseState.OnChange -= _warehouseHandler;
+        if (_alertHandler is not null) AlertState.OnChange -= _alertHandler;
+    }
+
+    private sealed record PollEntry(DateTime Time, string WarehouseId, int Count);
+
+    private static string GetWarehouseName(string id) =>
+        WarehouseState.AvailableWarehouses.FirstOrDefault(w => w.Id == id).Name ?? id;
+}
